import { describe, expect, it } from "vitest";
import { buildServer } from "./server.js";

const token = "seed-token-ada";

function bearer(value = token) {
  return { authorization: `Bearer ${value}` };
}

describe("auth, session, and project contract", () => {
  it("exposes health without authentication and includes a request id", async () => {
    const app = buildServer();
    const response = await app.inject({ method: "GET", url: "/health" });

    expect(response.statusCode).toBe(200);
    expect(response.json()).toMatchObject({ ok: true, service: "building-agent-api" });
    expect(response.json().requestId).toMatch(/^req_/);
  });

  it("logs in a seeded user without exposing the token in logs", async () => {
    const app = buildServer();
    const response = await app.inject({
      method: "POST",
      url: "/api/login",
      payload: { email: "ada@example.test", password: "local-dev-password" }
    });

    expect(response.statusCode).toBe(200);
    expect(response.json()).toEqual({
      token,
      user: { id: "user_ada", name: "Ada Lovelace" },
      requestId: expect.stringMatching(/^req_/)
    });
  });

  it("rejects empty credentials with a canonical error", async () => {
    const app = buildServer();
    const response = await app.inject({
      method: "POST",
      url: "/api/login",
      payload: { email: "", password: "" }
    });

    expect(response.statusCode).toBe(401);
    expect(response.json()).toEqual({
      error: {
        code: "auth_invalid",
        message: "Invalid credentials.",
        requestId: expect.stringMatching(/^req_/)
      }
    });
  });

  it("rejects missing, malformed, and unknown bearer tokens", async () => {
    const app = buildServer();

    const missing = await app.inject({ method: "GET", url: "/api/session" });
    expect(missing.statusCode).toBe(401);
    expect(missing.json().error).toMatchObject({ code: "auth_missing" });

    const malformed = await app.inject({
      method: "GET",
      url: "/api/session",
      headers: { authorization: "Token definitely-not-bearer" }
    });
    expect(malformed.statusCode).toBe(401);
    expect(malformed.json().error).toMatchObject({ code: "auth_invalid" });

    const unknown = await app.inject({
      method: "GET",
      url: "/api/session",
      headers: bearer("unknown-token")
    });
    expect(unknown.statusCode).toBe(401);
    expect(unknown.json().error).toMatchObject({ code: "auth_invalid" });
  });

  it("returns session and bounded authorized projects for a valid token", async () => {
    const app = buildServer();

    const session = await app.inject({ method: "GET", url: "/api/session", headers: bearer() });
    expect(session.statusCode).toBe(200);
    expect(session.json()).toEqual({
      session: {
        userId: "user_ada",
        projectId: null,
        permissions: []
      },
      requestId: expect.stringMatching(/^req_/)
    });

    const projects = await app.inject({ method: "GET", url: "/api/projects", headers: bearer() });
    expect(projects.statusCode).toBe(200);
    expect(projects.json()).toEqual({
      projects: [
        { id: "project_alpha", name: "Alpha Build", permissions: ["chat:read", "chat:write"] },
        { id: "project_beta", name: "Beta Build", permissions: ["chat:read"] }
      ],
      limit: 50,
      requestId: expect.stringMatching(/^req_/)
    });
  });

  it("selects an authorized project and rejects a forbidden project", async () => {
    const app = buildServer();

    const selected = await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/select",
      headers: bearer()
    });
    expect(selected.statusCode).toBe(200);
    expect(selected.json()).toEqual({
      session: {
        userId: "user_ada",
        projectId: "project_alpha",
        permissions: ["chat:read", "chat:write"]
      },
      requestId: expect.stringMatching(/^req_/)
    });

    const forbidden = await app.inject({
      method: "POST",
      url: "/api/projects/project_gamma/select",
      headers: bearer()
    });
    expect(forbidden.statusCode).toBe(403);
    expect(forbidden.json().error).toMatchObject({ code: "project_forbidden" });
  });
});

import { describe, expect, it } from "vitest";
import { buildServer } from "./server.js";

const adaToken = "seed-token-ada";
const graceToken = "seed-token-grace";

function bearer(value: string) {
  return { authorization: `Bearer ${value}` };
}

describe("project-scoped chat contract", () => {
  it("requires auth and a matching selected project before reading chat", async () => {
    const app = buildServer();

    const unauthorized = await app.inject({ method: "GET", url: "/api/projects/project_alpha/chat" });
    expect(unauthorized.statusCode).toBe(401);
    expect(unauthorized.json().error).toMatchObject({ code: "auth_missing" });

    const notSelected = await app.inject({
      method: "GET",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken)
    });
    expect(notSelected.statusCode).toBe(403);
    expect(notSelected.json().error).toMatchObject({ code: "project_not_selected" });
  });

  it("stores and returns chat messages only for the selected project", async () => {
    const app = buildServer();

    await app.inject({ method: "POST", url: "/api/projects/project_alpha/select", headers: bearer(adaToken) });
    const posted = await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken),
      payload: { message: "What should we build first?" }
    });

    expect(posted.statusCode).toBe(201);
    expect(posted.json()).toEqual({
      message: {
        id: "msg_000001",
        projectId: "project_alpha",
        userId: "user_ada",
        role: "user",
        content: "What should we build first?"
      },
      requestId: expect.stringMatching(/^req_/)
    });

    const alphaChat = await app.inject({
      method: "GET",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken)
    });
    expect(alphaChat.statusCode).toBe(200);
    expect(alphaChat.json()).toEqual({
      messages: [posted.json().message],
      limit: 50,
      requestId: expect.stringMatching(/^req_/)
    });

    await app.inject({ method: "POST", url: "/api/projects/project_beta/select", headers: bearer(adaToken) });
    const betaChat = await app.inject({
      method: "GET",
      url: "/api/projects/project_beta/chat",
      headers: bearer(adaToken)
    });
    expect(betaChat.statusCode).toBe(200);
    expect(betaChat.json().messages).toEqual([]);
  });

  it("rejects chat writes without selected project, write permission, or valid body", async () => {
    const app = buildServer();

    const notSelected = await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken),
      payload: { message: "Hello" }
    });
    expect(notSelected.statusCode).toBe(403);
    expect(notSelected.json().error).toMatchObject({ code: "project_not_selected" });

    await app.inject({ method: "POST", url: "/api/projects/project_beta/select", headers: bearer(adaToken) });
    const noWrite = await app.inject({
      method: "POST",
      url: "/api/projects/project_beta/chat",
      headers: bearer(adaToken),
      payload: { message: "Should not write" }
    });
    expect(noWrite.statusCode).toBe(403);
    expect(noWrite.json().error).toMatchObject({ code: "project_forbidden" });

    await app.inject({ method: "POST", url: "/api/projects/project_alpha/select", headers: bearer(adaToken) });
    for (const payload of [{}, { message: "" }, { message: "   " }, { message: "x".repeat(1001) }, { text: "wrong shape" }]) {
      const invalid = await app.inject({
        method: "POST",
        url: "/api/projects/project_alpha/chat",
        headers: bearer(adaToken),
        payload
      });
      expect(invalid.statusCode).toBe(422);
      expect(invalid.json().error).toMatchObject({ code: "chat_invalid" });
    }
  });

  it("rechecks membership on every operation and isolates projects between users", async () => {
    const app = buildServer();

    await app.inject({ method: "POST", url: "/api/projects/project_alpha/select", headers: bearer(adaToken) });
    await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken),
      payload: { message: "Alpha-only context" }
    });

    const graceForbidden = await app.inject({
      method: "GET",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(graceToken)
    });
    expect(graceForbidden.statusCode).toBe(403);
    expect(graceForbidden.json().error).toMatchObject({ code: "project_forbidden" });

    await app.inject({ method: "POST", url: "/api/projects/project_gamma/select", headers: bearer(graceToken) });
    const graceChat = await app.inject({
      method: "GET",
      url: "/api/projects/project_gamma/chat",
      headers: bearer(graceToken)
    });
    expect(graceChat.statusCode).toBe(200);
    expect(graceChat.json().messages).toEqual([]);
  });
});

export type Permission = "chat:read" | "chat:write";

export interface SeedUser {
  id: string;
  name: string;
  email: string;
  password: string;
}

export interface SeedProject {
  id: string;
  name: string;
}

export interface SeedMembership {
  userId: string;
  projectId: string;
  permissions: Permission[];
}

export interface ChatMessage {
  id: string;
  projectId: string;
  userId: string;
  role: "user";
  content: string;
}

export interface SessionState {
  userId: string;
  selectedProjectId: string | null;
}

export interface SeedStore {
  users: SeedUser[];
  tokens: Record<string, string>;
  projects: SeedProject[];
  memberships: SeedMembership[];
  messagesByProject: Record<string, ChatMessage[]>;
  sessionsByToken: Record<string, SessionState>;
  maxListSize: number;
  maxChatMessages: number;
}

export function createSeedStore(): SeedStore {
  const projects: SeedProject[] = [
    { id: "project_alpha", name: "Alpha Build" },
    { id: "project_beta", name: "Beta Build" },
    { id: "project_gamma", name: "Gamma Build" }
  ];

  return {
    users: [
      { id: "user_ada", name: "Ada Lovelace", email: "ada@example.test", password: "local-dev-password" },
      { id: "user_grace", name: "Grace Hopper", email: "grace@example.test", password: "local-dev-password" }
    ],
    tokens: {
      "seed-token-ada": "user_ada",
      "seed-token-grace": "user_grace"
    },
    projects,
    memberships: [
      { userId: "user_ada", projectId: "project_alpha", permissions: ["chat:read", "chat:write"] },
      { userId: "user_ada", projectId: "project_beta", permissions: ["chat:read"] },
      { userId: "user_grace", projectId: "project_gamma", permissions: ["chat:read", "chat:write"] }
    ],
    messagesByProject: Object.fromEntries(projects.map((project) => [project.id, [] as ChatMessage[]])),
    sessionsByToken: {},
    maxListSize: 50,
    maxChatMessages: 25
  };
}

export function cloneStore(store: SeedStore): SeedStore {
  return {
    users: store.users.map((user) => ({ ...user })),
    tokens: { ...store.tokens },
    projects: store.projects.map((project) => ({ ...project })),
    memberships: store.memberships.map((membership) => ({ ...membership, permissions: [...membership.permissions] })),
    messagesByProject: Object.fromEntries(
      Object.entries(store.messagesByProject).map(([projectId, messages]) => [
        projectId,
        messages.map((message) => ({ ...message }))
      ])
    ),
    sessionsByToken: Object.fromEntries(
      Object.entries(store.sessionsByToken).map(([token, session]) => [token, { ...session }])
    ),
    maxListSize: store.maxListSize,
    maxChatMessages: store.maxChatMessages
  };
}

export function seedStore(): SeedStore {
  return createSeedStore();
}

import type { FastifyReply, FastifyRequest } from "fastify";
import type { Permission, SeedMembership, SeedStore, SessionState } from "./seed.js";

export interface ApiSessionContext {
  token: string;
  userId: string;
  projectId: string | null;
  permissions: Permission[];
}

export interface ApiErrorBody {
  error: {
    code: string;
    message: string;
    requestId: string;
  };
}

export function requestIdFor(request: FastifyRequest): string {
  return String(request.id).startsWith("req_") ? String(request.id) : `req_${request.id}`;
}

export function errorResponse(
  request: FastifyRequest,
  code: string,
  message: string
): ApiErrorBody {
  return {
    error: {
      code,
      message,
      requestId: requestIdFor(request)
    }
  };
}

export function sendError(
  request: FastifyRequest,
  reply: FastifyReply,
  statusCode: number,
  code: string,
  message: string
): FastifyReply {
  return reply.status(statusCode).send(errorResponse(request, code, message));
}

function parseBearer(header: unknown): string | null {
  if (typeof header !== "string") {
    return null;
  }

  const parts = header.trim().split(/\s+/u);
  if (parts.length !== 2 || parts[0] !== "Bearer" || !parts[1]) {
    return null;
  }

  return parts[1];
}

function membershipFor(store: SeedStore, userId: string, projectId: string): SeedMembership | undefined {
  return store.memberships.find(
    (membership) => membership.userId === userId && membership.projectId === projectId
  );
}

export function getPermissionsForSelectedProject(store: SeedStore, session: SessionState): Permission[] {
  if (!session.selectedProjectId) {
    return [];
  }
  return membershipFor(store, session.userId, session.selectedProjectId)?.permissions ?? [];
}

export function authenticateRequest(
  request: FastifyRequest,
  reply: FastifyReply,
  store: SeedStore
): ApiSessionContext | FastifyReply {
  const authorization = request.headers.authorization;
  if (authorization === undefined) {
    return sendError(request, reply, 401, "auth_missing", "Missing bearer token.");
  }

  const token = parseBearer(authorization);
  if (!token) {
    return sendError(request, reply, 401, "auth_invalid", "Invalid bearer token.");
  }

  const userId = store.tokens[token];
  if (!userId) {
    return sendError(request, reply, 401, "auth_invalid", "Invalid bearer token.");
  }

  const session = store.sessionsByToken[token] ?? { userId, selectedProjectId: null };
  store.sessionsByToken[token] = session;

  return {
    token,
    userId,
    projectId: session.selectedProjectId,
    permissions: getPermissionsForSelectedProject(store, session)
  };
}

export function requireProjectMembership(
  request: FastifyRequest,
  reply: FastifyReply,
  store: SeedStore,
  session: ApiSessionContext,
  projectId: string
): SeedMembership | FastifyReply {
  const projectExists = store.projects.some((project) => project.id === projectId);
  const membership = membershipFor(store, session.userId, projectId);

  if (!projectExists || !membership) {
    return sendError(request, reply, 403, "project_forbidden", "Project is not available for this session.");
  }

  return membership;
}

export function requireSelectedProject(
  request: FastifyRequest,
  reply: FastifyReply,
  session: ApiSessionContext,
  projectId: string
): true | FastifyReply {
  if (session.projectId !== projectId) {
    return sendError(request, reply, 403, "project_not_selected", "Select this project before using project resources.");
  }

  return true;
}

export function requirePermission(
  request: FastifyRequest,
  reply: FastifyReply,
  membership: SeedMembership,
  permission: Permission
): true | FastifyReply {
  if (!membership.permissions.includes(permission)) {
    return sendError(request, reply, 403, "project_forbidden", "Project permission is required.");
  }

  return true;
}

import Fastify, { type FastifyInstance, type FastifyReply } from "fastify";
import cors from "@fastify/cors";
import {
  authenticateRequest,
  getPermissionsForSelectedProject,
  requestIdFor,
  requirePermission,
  requireProjectMembership,
  requireSelectedProject,
  sendError
} from "./auth.js";
import { createSeedStore, type ChatMessage, type SeedStore } from "./seed.js";

interface BuildServerOptions {
  store?: SeedStore;
}

interface ProjectParams {
  projectId: string;
}

interface LoginBody {
  email?: unknown;
  password?: unknown;
}

interface ChatBody {
  message?: unknown;
}

let messageSequence = 0;

function nextMessageId(): string {
  messageSequence += 1;
  return `msg_${String(messageSequence).padStart(6, "0")}`;
}

function bounded<T>(items: T[], limit: number): T[] {
  return items.slice(0, limit);
}

function isReply(value: unknown): value is FastifyReply {
  return typeof value === "object" && value !== null && "sent" in value;
}

function validateChatMessage(body: unknown): string | null {
  if (typeof body !== "object" || body === null || Array.isArray(body)) {
    return null;
  }

  const message = (body as ChatBody).message;
  if (typeof message !== "string") {
    return null;
  }

  const trimmed = message.trim();
  if (trimmed.length === 0 || trimmed.length > 1000) {
    return null;
  }

  return trimmed;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const store = options.store ?? createSeedStore();
  messageSequence = 0;

  const app = Fastify({
    logger: false,
    genReqId: (() => {
      let sequence = 0;
      return () => {
        sequence += 1;
        return `req_${String(sequence).padStart(6, "0")}`;
      };
    })()
  });

  void app.register(cors, { origin: true });

  app.get("/health", async (request) => ({
    ok: true,
    service: "building-agent-api",
    requestId: requestIdFor(request)
  }));

  app.post<{ Body: LoginBody }>("/api/login", async (request, reply) => {
    const { email, password } = request.body ?? {};
    if (typeof email !== "string" || typeof password !== "string" || !email.trim() || !password) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const user = store.users.find((candidate) => candidate.email === email && candidate.password === password);
    if (!user) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const token = Object.entries(store.tokens).find(([, userId]) => userId === user.id)?.[0];
    if (!token) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    store.sessionsByToken[token] = store.sessionsByToken[token] ?? { userId: user.id, selectedProjectId: null };

    return {
      token,
      user: { id: user.id, name: user.name },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/session", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      session: {
        userId: session.userId,
        projectId: session.projectId,
        permissions: session.permissions
      },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/projects", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const memberships = store.memberships.filter((membership) => membership.userId === session.userId);
    const projects = bounded(memberships, store.maxListSize).flatMap((membership) => {
      const project = store.projects.find((candidate) => candidate.id === membership.projectId);
      return project ? [{ id: project.id, name: project.name, permissions: membership.permissions }] : [];
    });

    return { projects, limit: store.maxListSize, requestId: requestIdFor(request) };
  });

  app.post<{ Params: ProjectParams }>("/api/projects/:projectId/select", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    store.sessionsByToken[session.token] = {
      userId: session.userId,
      selectedProjectId: request.params.projectId
    };

    return {
      session: {
        userId: session.userId,
        projectId: request.params.projectId,
        permissions: getPermissionsForSelectedProject(store, store.sessionsByToken[session.token])
      },
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    return {
      messages: bounded(store.messagesByProject[request.params.projectId] ?? [], store.maxListSize),
      limit: store.maxListSize,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams; Body: ChatBody }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const writable = requirePermission(request, reply, membership, "chat:write");
    if (isReply(writable)) {
      return writable;
    }

    const content = validateChatMessage(request.body);
    if (!content) {
      return sendError(request, reply, 422, "chat_invalid", "Chat message must be 1-1000 characters.");
    }

    const messages = store.messagesByProject[request.params.projectId] ?? [];
    const message: ChatMessage = {
      id: nextMessageId(),
      projectId: request.params.projectId,
      userId: session.userId,
      role: "user",
      content
    };
    messages.push(message);
    if (messages.length > store.maxChatMessages) {
      messages.splice(0, messages.length - store.maxChatMessages);
    }
    store.messagesByProject[request.params.projectId] = messages;

    return reply.status(201).send({ message, requestId: requestIdFor(request) });
  });

  app.setErrorHandler((error, request, reply) => {
    if (error.validation) {
      return sendError(request, reply, 422, "chat_invalid", "Request payload is invalid.");
    }

    request.log.error({ err: error, requestId: requestIdFor(request) }, "Unhandled API error");
    return sendError(request, reply, 500, "internal_error", "Unexpected API error.");
  });

  return app;
}

import { buildServer } from "./server.js";

const port = Number(process.env.PORT ?? 3000);
const host = process.env.HOST ?? "127.0.0.1";

const app = buildServer();

try {
  await app.listen({ port, host });
  app.log.info({ host, port }, "BuildingAgent API listening");
} catch (error) {
  app.log.error({ err: error }, "BuildingAgent API failed to start");
  process.exit(1);
}

